#include<bits/stdc++.h>
using namespace std;
long long ans=LLONG_MAX,sum,cnt,z=0;
int t,n,m;
long long a[501],d[15531],c[501];
int mid[15035];
int main()
{
    scanf("%d",&t);
    while(t--)
    {
        scanf("%d%d",&n,&m);
        int tot=1;
        ans=LLONG_MAX,z=0;
        for(int i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
            for(int j=a[i];j;j/=2)
            {
                mid[++z]=j;
            }
        }
        sort(mid+1,mid+1+z);
        for(int i=2;i<=z;i++)
        {
            if(mid[i]!=mid[i-1])
            {
                mid[++tot]=mid[i];
            }
        }
        for(int x=1;x<=tot;x++)
        {
            sum=0;
            for(int i=1;i<=n;i++)
            {
                c[i]=LLONG_MAX;
                cnt=0;
                for(int j=a[i];j;j/=2,cnt++)
                {
                    c[i]=min(c[i],cnt+abs(j-mid[x]));
                }
            }
            sort(c+1,c+1+n);
            for(int i=1;i<=n-m;i++)
            {
                sum+=c[i];
            }
            ans=min(ans,sum);
        }
        printf("%lld\n",ans);
    }
    return 0;
}
